class Solution:
    def maxDistance(self, colors):
        n = len(colors)
        c0 = colors[0]
        cn = colors[-1]
        best = 0
        for i in range(n):
            if colors[i] != c0:
                best = max(best, i)
            if colors[i] != cn:
                best = max(best, n - 1 - i)
        return best

