var maxDistance = function(colors) {
    const n = colors.length;
    const c0 = colors[0];
    const cn = colors[n - 1];
    let best = 0;
    for (let i = 0; i < n; i++) {
        if (colors[i] !== c0) best = Math.max(best, i);
        if (colors[i] !== cn) best = Math.max(best, n - 1 - i);
    }
    return best;
};
